static void CliBuildCompilesEnumDeclarationApi()
{
    WithWorkspace(root =>
    {
        var manifestPath = WriteManifest(root, """
            [project]
            name = "EnumDeclarationApi"
            targetFramework = "net48"
            outputType = "library"
            rootNamespace = "Samples.Enums"
            generatedOutputRoot = "generated"
            """);
        WriteFile(root, "src/Main.tysh", """
            namespace Samples.Enums

            import { FlagsAttribute, ObsoleteAttribute } from "System"

            [FlagsAttribute]
            public enum Color : byte {
              Red = 1,
              Crimson = Red,
              [ObsoleteAttribute("Use Blue instead.")]
              Green,
              Blue = 4,
              Purple = Red | Blue
            }

            export fun favorite(): Color =
              Color.Red | Color.Blue

            export fun bluePart(input: Color): Color =
              input & Color.Blue

            export fun toggled(input: Color): Color =
              input ^ Color.Blue

            export fun inverted(input: Color): Color =
              ~input
            """);
